import { RefObject, useRef } from "react"
import style from "./ProjectSection.module.css"
import gsap from "gsap"
import { useGSAP } from "@gsap/react"
import { ScrollTrigger } from "gsap/ScrollTrigger";
import ProjectName from "./ProjectName/ProjectName";

gsap.registerPlugin(useGSAP);
gsap.registerPlugin(ScrollTrigger);

export default function ProjectSection({timeline, scrollref, triggerRef}:{timeline?:gsap.core.Timeline, scrollref:RefObject<never>, triggerRef:RefObject<never>}) {

    const sectionRef = useRef<HTMLElement>(null!)
    const circleRef = useRef<SVGCircleElement>(null!)

    useGSAP(() => {

        const timelineProject = gsap.timeline(
                    {scrollTrigger : {
                            trigger : triggerRef.current,
                            scroller : scrollref.current,
                            start: 'top top', // when the top of the trigger hits the top of the viewport
                            end : 'bottom top',
                            markers : false,
                            scrub : 1,
                        }}
                    )
                .set("."+style.title, {display : "flex"})
                .to("."+style.title, 
                    {opacity: "1", duration : 1}
                )
                .to("."+style.circle, 
                    {opacity: "1", duration : 1}
                )

                .to({}, {duration : 1})

                .to("."+style.circle, 
                    {opacity: "0", duration : 1}
                )
                .to("."+style.title, 
                    {opacity: "0", duration: 1}
                )
                .to({}, {duration : 1})
                .set("."+style.title, {display : "none"})
        
        ScrollTrigger.refresh();

    }, {scope : sectionRef})

    return (
        <section ref={sectionRef} className={style.projectsSection}>
            <h1 className={style.title}>Projects</h1>

            <svg className={style.circle} width="170" height="170" viewBox="0 0 170 170" fill="none" xmlns="http://www.w3.org/2000/svg">
                <circle ref={circleRef} cx="85" cy="85" r="83" stroke="#f8f9fa" strokeWidth="2"/>
            </svg>

            <ProjectName name={"test"} percent={0.5}/>
        </section>
    )
}